document.addEventListener("DOMContentLoaded",(function(){const memberCheckboxes=document.querySelectorAll(".member-checkbox"),headSelect=document.getElementById("head_constituent_id"),memberCountEl=document.getElementById("memberCount");document.querySelectorAll(".member-check-item").forEach((item=>{item.addEventListener("click",(function(e){if("LABEL"===e.target.tagName||"INPUT"===e.target.tagName)return;const checkbox=item.querySelector(".member-checkbox");checkbox.checked=!checkbox.checked,checkbox.dispatchEvent(new Event("change"))}))})),memberCheckboxes.forEach((checkbox=>{checkbox.addEventListener("change",(function(){const item=this.closest(".member-check-item");this.checked?item.classList.add("is-checked"):item.classList.remove("is-checked"),function(){const currentVal=headSelect.value;for(;headSelect.options.length>1;)headSelect.remove(1);memberCheckboxes.forEach((checkbox=>{if(checkbox.checked){const name=checkbox.closest(".member-check-item").dataset.name,option=new Option(name,checkbox.value);headSelect.add(option)}})),currentVal&&(headSelect.value=currentVal)}(),function(){const count=Array.from(memberCheckboxes).filter((cb=>cb.checked)).length;memberCountEl.textContent=count}()}))}))}));